/* Optimizer: prodigy, Variant: S_F_M */


template <typename scalar_t>
__launch_bounds__(256, 8)
__global__ __launch_bounds__(256, 2) void prodigy_step_moe_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    float* __restrict__ exp_avg,
    float* __restrict__ exp_avg_sq,
    float* __restrict__ s,
    const bool* __restrict__ active_mask,
    const float d_lr,
    const float beta1,
    const float beta2,
    const float lr,
    const float weight_decay,
    const float eps,
    const float bc1,
    const float bc2,
    const int N
) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit: skip inactive expert parameters
    if (!active_mask[idx]) return;

    const float g = static_cast<float>(grad[idx]);

    const float d_lr_g = d_lr * g;
    const float d_lr_g_sq = d_lr * d_lr * g * g;
    // Update s (EMA of d_lr-scaled squared gradients)
    const float s_old = stream_load(&s[idx]);
    const float s_new = beta2 * s_old + (1.0f - beta2) * d_lr_g_sq;
    stream_store(&s[idx], s_new);

    const float exp_avg_val = stream_load(&exp_avg[idx]);
    const float exp_avg_sq_val = stream_load(&exp_avg_sq[idx]);

    const float ea = beta1 * exp_avg_val + (1.0f - beta1) * d_lr_g;
    const float easq = beta2 * exp_avg_sq_val + (1.0f - beta2) * d_lr_g_sq;

    stream_store(&exp_avg[idx], ea);
    stream_store(&exp_avg_sq[idx], easq);

    const float step_size = lr / bc1;
    const float denom = sqrtf(easq / bc2) + d_lr * eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * d_lr * weight_decay);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

void launch_prodigy_step_moe(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor exp_avg,
    torch::Tensor exp_avg_sq,
    torch::Tensor s,
    torch::Tensor active_mask,
    float d_lr,
    float beta1,
    float beta2,
    float lr,
    float weight_decay,
    float eps,
    float bc1,
    float bc2
) {
    const int N = param.numel();
    if (N == 0) return;

    const int grid = (N + 256 - 1) / 256;
    AT_DISPATCH_FLOATING_TYPES_AND2(
        at::ScalarType::Half, at::ScalarType::BFloat16,
        param.scalar_type(), "launch_prodigy_step_moe", ([&] {
        prodigy_step_moe_kernel<scalar_t><<<grid, 256>>>(
            param.data_ptr<scalar_t>(),
            grad.data_ptr<scalar_t>(),
            exp_avg.data_ptr<float>(),
            exp_avg_sq.data_ptr<float>(),
            s.data_ptr<float>(),
            active_mask.data_ptr<bool>(),
            d_lr,
            beta1,
            beta2,
            lr,
            weight_decay,
            eps,
            bc1,
            bc2,
            N);
    }));
}


/* Optimizer: prodigy, Variant: V_F_M */


__launch_bounds__(256, 8)
__global__ __launch_bounds__(256, 2) void prodigy_step_moe_vec4_kernel(
    float4* __restrict__ param4,
    const float4* __restrict__ grad4,
    float4* __restrict__ exp_avg4,
    float4* __restrict__ exp_avg_sq4,
    float4* __restrict__ s4,
    const bool* __restrict__ active_mask,
    const float d_lr,
    const float beta1,
    const float beta2,
    const float lr,
    const float weight_decay,
    const float eps,
    const float bc1,
    const float bc2,
    const int N4
) {
    const int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i >= N4) return;

    // MoE early-exit
    if (!active_mask[i*4] && !active_mask[i*4+1] &&
        !active_mask[i*4+2] && !active_mask[i*4+3]) return;

    float4 p = param4[i];
    float4 g = grad4[i];
    float4 exp_avg_v = stream_load4(&exp_avg4[i]);
    float4 exp_avg_sq_v = stream_load4(&exp_avg_sq4[i]);
    float4 s_v = stream_load4(&s4[i]);

    // Component x
    const float d_lr_g = d_lr * g.x;
    const float d_lr_g_sq = d_lr * d_lr * g.x * g.x;
    const float s_old = s_v.x;
    const float s_new = beta2 * s_old + (1.0f - beta2) * d_lr_g_sq;
    s_v.x = s_new;
    // Component y
    const float d_lr_g = d_lr * g.y;
    const float d_lr_g_sq = d_lr * d_lr * g.y * g.y;
    const float s_old = s_v.y;
    const float s_new = beta2 * s_old + (1.0f - beta2) * d_lr_g_sq;
    s_v.y = s_new;
    // Component z
    const float d_lr_g = d_lr * g.z;
    const float d_lr_g_sq = d_lr * d_lr * g.z * g.z;
    const float s_old = s_v.z;
    const float s_new = beta2 * s_old + (1.0f - beta2) * d_lr_g_sq;
    s_v.z = s_new;
    // Component w
    const float d_lr_g = d_lr * g.w;
    const float d_lr_g_sq = d_lr * d_lr * g.w * g.w;
    const float s_old = s_v.w;
    const float s_new = beta2 * s_old + (1.0f - beta2) * d_lr_g_sq;
    s_v.w = s_new;

    const float ea_x = beta1 * exp_avg_v.x + (1.0f - beta1) * d_lr_g.x;
    const float easq_x = beta2 * exp_avg_sq_v.x + (1.0f - beta2) * d_lr_g.x_sq;
    const float ea_y = beta1 * exp_avg_v.y + (1.0f - beta1) * d_lr_g.y;
    const float easq_y = beta2 * exp_avg_sq_v.y + (1.0f - beta2) * d_lr_g.y_sq;
    const float ea_z = beta1 * exp_avg_v.z + (1.0f - beta1) * d_lr_g.z;
    const float easq_z = beta2 * exp_avg_sq_v.z + (1.0f - beta2) * d_lr_g.z_sq;
    const float ea_w = beta1 * exp_avg_v.w + (1.0f - beta1) * d_lr_g.w;
    const float easq_w = beta2 * exp_avg_sq_v.w + (1.0f - beta2) * d_lr_g.w_sq;

    float4 exp_avg_out;
    exp_avg_out.x = ea_x;
    exp_avg_out.y = ea_y;
    exp_avg_out.z = ea_z;
    exp_avg_out.w = ea_w;
    stream_store4(&exp_avg4[i], exp_avg_out);
    float4 exp_avg_sq_out;
    exp_avg_sq_out.x = easq_x;
    exp_avg_sq_out.y = easq_y;
    exp_avg_sq_out.z = easq_z;
    exp_avg_sq_out.w = easq_w;
    stream_store4(&exp_avg_sq4[i], exp_avg_sq_out);

    const float step_size = lr / bc1;
    const float decay = 1.0f - lr * d_lr * weight_decay;
    p.x = decay * p.x - step_size * ea_x / (sqrtf(easq_x / bc2) + d_lr * eps);
    p.y = decay * p.y - step_size * ea_y / (sqrtf(easq_y / bc2) + d_lr * eps);
    p.z = decay * p.z - step_size * ea_z / (sqrtf(easq_z / bc2) + d_lr * eps);
    p.w = decay * p.w - step_size * ea_w / (sqrtf(easq_w / bc2) + d_lr * eps);
    param4[i] = p;
}

void launch_prodigy_step_moe_vec4(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor exp_avg,
    torch::Tensor exp_avg_sq,
    torch::Tensor s,
    torch::Tensor active_mask,
    float d_lr,
    float beta1,
    float beta2,
    float lr,
    float weight_decay,
    float eps,
    float bc1,
    float bc2
) {
    const int N = param.numel();
    if (N == 0) return;

    const int N4 = N / 4;
    const int grid = (N4 + 256 - 1) / 256;
    prodigy_step_moe_vec4_kernel<<<grid, 256>>>(
        reinterpret_cast<float4*>(param.data_ptr<float>()),
        reinterpret_cast<const float4*>(grad.data_ptr<float>()),
        reinterpret_cast<float4*>(exp_avg.data_ptr<float>()),
        reinterpret_cast<float4*>(exp_avg_sq.data_ptr<float>()),
        reinterpret_cast<float4*>(s.data_ptr<float>()),
        active_mask.data_ptr<bool>(),
        d_lr,
        beta1,
        beta2,
        lr,
        weight_decay,
        eps,
        bc1,
        bc2,
        N4);
}


