// Philox RNG (stateless)

// INT4 stochastic rounding

template <typename scalar_t>
__launch_bounds__(256, 8)
__global__ __launch_bounds__(256, 2) void prodigy_step_moe_q4_kernel(
    scalar_t* __restrict__ param,
    const scalar_t* __restrict__ grad,
    int8_t* __restrict__ exp_avg_q,
    float* __restrict__ exp_avg_scales,
    int8_t* __restrict__ exp_avg_sq_q,
    float* __restrict__ exp_avg_sq_scales,
    __nv_bfloat16* __restrict__ s_bf16,
    const bool* __restrict__ active_mask,
    const float d_lr,
    const float beta1,
    const float beta2,
    const float lr,
    const float weight_decay,
    const float eps,
    const float bc1,
    const float bc2,
    const unsigned global_step,
    const int N
) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N) return;

    // MoE early-exit: skip inactive expert parameters
    if (!active_mask[idx]) return;

    const float g = static_cast<float>(grad[idx]);

    const float d_lr_g = d_lr * g;
    const float d_lr_g_sq = d_lr * d_lr * g * g;
    // Update s (EMA of d_lr-scaled squared gradients)
    const float s_old = s_val;
    const float s_new = beta2 * s_old + (1.0f - beta2) * d_lr_g_sq;
    /* q4 store s */ s_val = s_new; /* stored below */;

    float exp_avg_val;
    {
        const int _blk = idx / 8;
        exp_avg_val = (float)exp_avg_q[idx] * exp_avg_scales[_blk];
    }
    float exp_avg_sq_val;
    {
        const int _blk = idx / 8;
        exp_avg_sq_val = (float)exp_avg_sq_q[idx] * exp_avg_sq_scales[_blk];
    }

    const float ea = beta1 * exp_avg_val + (1.0f - beta1) * d_lr_g;
    const float easq = beta2 * exp_avg_sq_val + (1.0f - beta2) * d_lr_g_sq;

        {
        const int _blk = idx / 8;
        float _new_scale = fmaxf(fabsf(ea), 1e-12f) / 127.0f;
        unsigned _rng = philox_hash_gen(global_step * 2u, (unsigned)idx);
        exp_avg_q[idx] = float_to_int8_stochastic(ea, _new_scale, _rng);
        if (idx % 8 == 0) exp_avg_scales[_blk] = _new_scale;
    }
        {
        const int _blk = idx / 8;
        float _new_scale = fmaxf(fabsf(easq), 1e-12f) / 127.0f;
        unsigned _rng = philox_hash_gen(global_step * 3u, (unsigned)idx);
        exp_avg_sq_q[idx] = float_to_int8_stochastic(easq, _new_scale, _rng);
        if (idx % 8 == 0) exp_avg_sq_scales[_blk] = _new_scale;
    }

    const float step_size = lr / bc1;
    const float denom = sqrtf(easq / bc2) + d_lr * eps;
    float p = static_cast<float>(param[idx]);
    p *= (1.0f - lr * d_lr * weight_decay);
    p -= step_size * ea / denom;
    param[idx] = static_cast<scalar_t>(p);
}

