        unsigned _rng = philox_hash_gen(global_step * 3u, (unsigned)i*4+2);
        exp_avg_sq_q[i*4+2] = float_to_int8_stochastic(easq_z, _new_scale, _rng);
        if (i*4+2 % 8 == 0) exp_avg_sq_scales[_blk] = _new_scale;
    }
        {
        const int _blk = i*4+3 / 8;
        float _new_scale = fmaxf(fabsf(easq_w), 1e-12f) / 127.0f;
        unsigned _rng = philox_hash_gen(global_step * 3u, (unsigned)i*4+3);
        exp_avg_sq_q[i*4+3] = float_to_int8_stochastic(easq_w, _new_scale, _rng);
        if (i*4+3 % 8 == 0) exp_avg_sq_scales[_blk] = _new_scale;
    }

    const float step_size = lr / bc1;
    const float decay = 1.0f - lr * d_lr * weight_decay;
    p.x = decay * p.x - step_size * ea_x / (sqrtf(easq_x / bc2) + d_lr * eps);
    p.y = decay * p.y - step_size * ea_y / (sqrtf(easq_y / bc2) + d_lr * eps);
    p.z = decay * p.z - step_size * ea_z / (sqrtf(easq_z / bc2) + d_lr * eps);
    p.w = decay * p.w - step_size * ea_w / (sqrtf(easq_w / bc2) + d_lr * eps);
    param4[i] = p;
}

void launch_prodigy_step_moe_q4_vec4(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor exp_avg_q,
    torch::Tensor exp_avg_scales,
    torch::Tensor exp_avg_sq_q,
    torch::Tensor exp_avg_sq_scales,
    torch::Tensor s_q,
    torch::Tensor active_mask,
    float d_lr,
    float beta1,
    float beta2,
    float lr,
    float weight_decay,
    float eps,
    float bc1,
    float bc2,
    int global_step
) {
    const int N = param.numel();
    if (N == 0) return;

    const int N4 = N / 4;
    const int grid = (N4 + 256 - 1) / 256;
    prodigy_step_moe_q4_vec4_kernel<<<grid, 256>>>(
        reinterpret_cast<float4*>(param.data_ptr<float>()),
        reinterpret_cast<const float4*>(grad.data_ptr<float>()),
        exp_avg_q.data_ptr<int8_t>(),
        exp_avg_scales.data_ptr<float>(),
        exp_avg_sq_q.data_ptr<int8_t>(),
        exp_avg_sq_scales.data_ptr<float>(),
        reinterpret_cast<__nv_bfloat16*>(s_q.data_ptr()),
        active_mask.data_ptr<bool>(),
        d_lr,
        beta1,
        beta2,
        lr,
        weight_decay,
        eps,
        bc1,
        bc2,
        static_cast<unsigned>(global_step),
        N4);
}


